const text = $input.first().json.message.text;
const chatId = $input.first().json.message.chat.id;
const isURL = text.startsWith('http');

return [{
  json: {
    raw_input: text,
    chat_id:   chatId,
    is_url:    isURL,
    email:     isURL ? '' : text.trim(),
    job_url:   isURL ? text.trim() : ''
  }
}];

const jobDetails = $input.first().json.job_details;
const chatId = $input.first().json.chat_id;
const email = $input.first().json.email;

// Hardcoded CV summaries for each CV type
const cvSummaries = {
  'cv_ai_data_trainer': {
    summary: 'Experienced AI Data Trainer specializing in machine learning model evaluation, data annotation, and quality assurance for AI systems.',
    key_skills: 'Machine Learning, Data Annotation, Model Evaluation, Quality Assurance, Python, TensorFlow, Data Analysis',
    experience_highlights: 'Led data annotation projects improving model accuracy by 25%, Evaluated and refined ML models for production deployment, Managed quality control processes for AI training datasets',
    education: 'Bachelor of Science in Computer Science'
  },
  'cv_data_analyst': {
    summary: 'Results-driven Data Analyst with expertise in business intelligence, data visualization, and statistical analysis to drive data-informed decision making.',
    key_skills: 'Data Analysis, SQL, Python, Tableau, Power BI, Statistical Analysis, Business Intelligence, Excel',
    experience_highlights: 'Developed dashboards that increased operational efficiency by 30%, Conducted statistical analysis leading to $500K cost savings, Automated reporting processes reducing manual work by 40%',
    education: 'Bachelor of Science in Data Science'
  },
  'cv_ai_automation_engineer': {
    summary: 'Innovative AI Automation Engineer focused on building intelligent workflows, process automation, and AI-powered solutions to optimize business operations.',
    key_skills: 'AI Automation, Workflow Design, Python, n8n, Zapier, API Integration, Process Optimization, Machine Learning Integration',
    experience_highlights: 'Designed AI-powered automation systems saving 100+ hours monthly, Integrated LLM APIs into business workflows increasing productivity by 45%, Built end-to-end automation solutions for enterprise clients',
    education: 'Bachelor of Engineering in Software Engineering'
  }
};

// Convert to lowercase for case-insensitive matching
const jobDetailsLower = jobDetails.toLowerCase();

// Default CV choice
let cvChoice = 'cv_data_analyst';

// Check AI Data Trainer first
if (jobDetailsLower.includes('ai data trainer') || 
    jobDetailsLower.includes('data trainer') || 
    jobDetailsLower.includes('data labelling') || 
    jobDetailsLower.includes('data labeling') || 
    jobDetailsLower.includes('prompt engineering') || 
    jobDetailsLower.includes('model evaluation')) {
  cvChoice = 'cv_ai_data_trainer';
} 
// Then check Data Analyst
else if (jobDetailsLower.includes('data analyst') || 
         jobDetailsLower.includes('analyst') || 
         jobDetailsLower.includes('power bi') || 
         jobDetailsLower.includes('sql') || 
         jobDetailsLower.includes('reporting') || 
         jobDetailsLower.includes('business intelligence')) {
  cvChoice = 'cv_data_analyst';
} 
// Then check AI Automation Engineer
else if (jobDetailsLower.includes('ai automation') || 
         jobDetailsLower.includes('automation engineer') || 
         jobDetailsLower.includes('n8n') || 
         jobDetailsLower.includes('zapier') || 
         jobDetailsLower.includes('workflow') || 
         jobDetailsLower.includes('ai agents') || 
         jobDetailsLower.includes('ai agent') || 
         jobDetailsLower.includes('process automation')) {
  cvChoice = 'cv_ai_automation_engineer';
}

const selectedCV = cvSummaries[cvChoice];

return [{
  json: {
    job_details: jobDetails,
    cv_choice: cvChoice,
    cv_summary: selectedCV.summary,
    key_skills: selectedCV.key_skills,
    experience_highlights: selectedCV.experience_highlights,
    education: selectedCV.education,
    chat_id: chatId,
    email: email
  }
}];
